        AppDestination.getBottomItems().forEach { destination ->

@OptIn(androidx.compose.material3.ExperimentalMaterial3Api::class)
@Composable
fun SupermarketBottomBar(
    navController: NavHostController,
    currentDestination: NavDestination?
) {
    NavigationBar(
        containerColor = MaterialTheme.colorScheme.primaryContainer
    ) {
        AppDestination.bottomItems.forEach { destination ->
            NavigationBarItem(
                selected = currentDestination
                    ?.hierarchy
                    ?.any { it.route == destination.route } == true,
                onClick = {
                    navController.navigate(destination.route) {
                        if (destination.route == AppDestination.Cart.route && cartBadgeCount > 0) {
                            BadgedBox(
                                badge = {
                                    Badge {
                                        Text(if (cartBadgeCount > 99) "99+" else cartBadgeCount.toString())
                                    }
                                }
                            ) {
                                Icon(imageVector = it, contentDescription = destination.label)
                            }
                        } else {
                            Icon(imageVector = it, contentDescription = destination.label)
                        }
                            BadgedBox(
                                badge = {
                                    Badge { Text(text = cartBadgeCount.toString()) }
                                }
                            ) {
                                Icon(imageVector = it, contentDescription = destination.label)
                            }
                        } else {
                            Icon(imageVector = it, contentDescription = destination.label)
                        }
                        launchSingleTop = true
                        restoreState = true
                    }
                },
                icon = {
                    destination.icon?.let {
                        Icon(imageVector = it, contentDescription = destination.label)
                    }
                },
                label = { Text(text = destination.label) },
                colors = NavigationBarItemDefaults.colors(
                    selectedIconColor = MaterialTheme.colorScheme.primary,
                    selectedTextColor = MaterialTheme.colorScheme.primary,
                    indicatorColor = MaterialTheme.colorScheme.surface,
                    unselectedIconColor = MaterialTheme.colorScheme.onPrimaryContainer,
                    unselectedTextColor = MaterialTheme.colorScheme.onPrimaryContainer
                )
            )
        }
    }
}

package com.example.altafedeltium.ui.components

import androidx.compose.material3.Icon
import androidx.compose.material3.NavigationBar
import androidx.compose.material3.NavigationBarItem
import androidx.compose.material3.NavigationBarItemDefaults
import androidx.compose.material3.MaterialTheme
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.navigation.NavDestination
import androidx.navigation.NavDestination.Companion.hierarchy
import androidx.navigation.NavHostController
import com.example.altafedeltium.ui.navigation.AppDestination

@Composable
fun SupermarketBottomBar(
    navController: NavHostController,
    currentDestination: NavDestination?
) {
    NavigationBar(
        containerColor = MaterialTheme.colorScheme.primaryContainer
    ) {
        AppDestination.bottomItems.forEach { destination ->
            NavigationBarItem(
                selected = currentDestination
                    ?.hierarchy
                    ?.any { it.route == destination.route } == true,
                onClick = {
                    navController.navigate(destination.route) {
                        popUpTo(AppDestination.Home.route) { saveState = true }
                        launchSingleTop = true
                        restoreState = true
                    }
                },
                icon = {
                    destination.icon?.let {
                        Icon(imageVector = it, contentDescription = destination.label)
                    }
                },
                label = { Text(text = destination.label) },
                colors = NavigationBarItemDefaults.colors(
                    selectedIconColor = MaterialTheme.colorScheme.primary,
                    selectedTextColor = MaterialTheme.colorScheme.primary,
                    indicatorColor = MaterialTheme.colorScheme.surface,
                    unselectedIconColor = MaterialTheme.colorScheme.onPrimaryContainer,
                    unselectedTextColor = MaterialTheme.colorScheme.onPrimaryContainer
                )
            )
        }
    }
}

