import androidx.compose.ui.unit.dp
import com.example.altafedeltium.ui.components.JobCard
import com.example.altafedeltium.ui.viewmodel.JobSearchViewModel

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun WorkScreen(
    viewModel: JobSearchViewModel,
    onApply: (Int) -> Unit,
    onMyApplications: () -> Unit,
    modifier: Modifier = Modifier
) {
    val uiState by viewModel.uiState
    val filtered = viewModel.filteredPositions()
    val activeFilters = viewModel.activeFiltersSummary()
    val hasActiveFilters = viewModel.hasActiveFilters()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Opportunità di Lavoro") },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer,
                    titleContentColor = MaterialTheme.colorScheme.onPrimaryContainer
                )
            )
        },
        floatingActionButton = {
            ExtendedFloatingActionButton(
                onClick = onMyApplications,
                icon = { Icon(Icons.Default.WorkHistory, contentDescription = null) },
                text = { Text("Le mie Candidature") }
            )
        },
        modifier = modifier
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
        ) {
            // ── Barra di ricerca ──────────────────────────────────────
            OutlinedTextField(
                value = uiState.searchQuery,
                onValueChange = viewModel::onSearchQueryChanged,
                label = { Text("Cerca ruolo o azienda…") },
                leadingIcon = { Icon(Icons.Default.Search, contentDescription = null) },
                singleLine = true,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp)
            )

            // ── Filtro Città ──────────────────────────────────────────
            CityDropdown(
                cities = viewModel.cities,
                selected = uiState.selectedCity,
                onSelected = viewModel::onCitySelected,
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 2.dp)
            )

            // ── Filtro Distanza ───────────────────────────────────────
            Text(
                text = "Distanza massima",
                style = MaterialTheme.typography.labelMedium,
                modifier = Modifier.padding(horizontal = 16.dp, vertical = 4.dp)
            )
            LazyRow(
                contentPadding = PaddingValues(horizontal = 16.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(viewModel.distanceOptions) { km ->
                    FilterChip(
                        selected = uiState.maxDistanceKm == km,
                        onClick = { viewModel.onMaxDistanceChanged(km) },
                        label = { Text("≤ $km km") }
                    )
                }
            }

            // ── Filtro Ruolo ──────────────────────────────────────────
            Text(
                text = "Ruolo",
                style = MaterialTheme.typography.labelMedium,
                modifier = Modifier.padding(horizontal = 16.dp, vertical = 4.dp)
            )
            LazyRow(
                contentPadding = PaddingValues(horizontal = 16.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(viewModel.categories) { category ->
                    FilterChip(
                        selected = uiState.selectedCategory == category,
                        onClick = { viewModel.onCategorySelected(category) },
                        label = { Text(category.label) }
                    )
                }
            }

            // ── Lista Posizioni ───────────────────────────────────────
            if (hasActiveFilters) {
                LazyRow(
                    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 6.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    items(activeFilters) { filterText ->
                        AssistChip(
                            onClick = {},
                            label = { Text(filterText) }
                        )
                    }
                    item {
                        OutlinedButton(onClick = viewModel::resetFilters) {
                            Icon(
                                imageVector = Icons.Default.FilterAltOff,
                                contentDescription = null
                            )
                            Text("  Reset filtri")
                        }
                    }
                }
            }

            if (filtered.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text(
                            "Nessuna posizione trovata",
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            "Prova ad aumentare la distanza, cambiare città o resettare i filtri.",
                            style = MaterialTheme.typography.bodySmall
                        )
                        if (hasActiveFilters) {
                            OutlinedButton(
                                onClick = viewModel::resetFilters,
                                modifier = Modifier.padding(top = 12.dp)
                            ) {
                                Text("Mostra tutte le posizioni")
                            }
                        }
                    }
                }
            } else {
                LazyColumn(
                    contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    item {
                        Text(
                            text = "${filtered.size} posizione${if (filtered.size == 1) "" else "i"} trovata${if (filtered.size == 1) "" else "e"}",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.6f)
                        )
                    }
                    items(filtered, key = { it.id }) { position ->
                        JobCard(
                            position = position,
                            onApply = { onApply(position.id) }
                        )
                    }
                }
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun CityDropdown(
    cities: List<String>,
    selected: String,
    onSelected: (String) -> Unit,
    modifier: Modifier = Modifier
) {
    var expanded by remember { mutableStateOf(false) }
    ExposedDropdownMenuBox(
        expanded = expanded,
        onExpandedChange = { expanded = !expanded },
        modifier = modifier
    ) {
        OutlinedTextField(
            value = selected,
            onValueChange = {},
            readOnly = true,
            label = { Text("Città") },
            trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = expanded) },
            modifier = Modifier
                .menuAnchor(type = MenuAnchorType.PrimaryNotEditable, enabled = true)
                .fillMaxWidth()
        )
        ExposedDropdownMenu(
            expanded = expanded,
            onDismissRequest = { expanded = false }
        ) {
            cities.forEach { city ->
                DropdownMenuItem(
                    text = { Text(city) },
                    onClick = {
                        onSelected(city)
                        expanded = false
                    }
                )
            }
        }
    }
}

